// Generated by AI (UnitTest MCP)
//! Tool definitions and dispatch for the Lodestar MCP server.

mod conformance;
mod constitution;
mod executive;
mod knowledge;
mod lifecycle;

use lodestar_core::Lodestar;
use serde::Serialize;
use serde_json::{json, Value};

/// The advertised tool list (`tools/list`).
pub fn list() -> Vec<Value> {
    let mut tools = constitution::definitions();
    tools.extend(executive::definitions());
    tools.extend(conformance::definitions());
    tools.extend(knowledge::definitions());
    tools.extend(lifecycle::definitions());
    tools
}

/// Dispatch a `tools/call`. Returns the MCP `content` object or an error string.
pub fn call(engine: &Lodestar, params: &Value) -> Result<Value, String> {
    let name = params.get("name").and_then(Value::as_str).unwrap_or("");
    let args = params.get("arguments").cloned().unwrap_or(Value::Null);

    if let Some(result) = constitution::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = executive::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = conformance::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = knowledge::dispatch(engine, name, &args) {
        return result;
    }
    if let Some(result) = lifecycle::dispatch(engine, name, &args) {
        return result;
    }

    Err(format!("unknown tool: {name}"))
}

// ---- helpers ---------------------------------------------------------------

pub(super) fn req_str<'a>(args: &'a Value, key: &str) -> Result<&'a str, String> {
    args.get(key)
        .and_then(Value::as_str)
        .ok_or_else(|| format!("missing required string arg: {key}"))
}

pub(super) fn opt_str(args: &Value, key: &str) -> Option<String> {
    args.get(key)
        .and_then(Value::as_str)
        .filter(|s| !s.is_empty())
        .map(|s| s.to_string())
}

pub(super) fn optional_string_arg(args: &Value, key: &str) -> Result<Option<String>, String> {
    match args.get(key) {
        None | Some(Value::Null) => Ok(None),
        Some(Value::String(value)) if !value.trim().is_empty() => Ok(Some(value.clone())),
        Some(Value::String(_)) => Err(format!("argument {key} must not be empty")),
        Some(_) => Err(format!("argument {key} must be a string")),
    }
}

pub(super) fn i64_arg(args: &Value, key: &str, default: i64) -> i64 {
    args.get(key).and_then(Value::as_i64).unwrap_or(default)
}

pub(super) fn bool_arg(args: &Value, key: &str, default: bool) -> bool {
    args.get(key).and_then(Value::as_bool).unwrap_or(default)
}

pub(super) fn str_array(args: &Value, key: &str) -> Vec<String> {
    args.get(key)
        .and_then(Value::as_array)
        .map(|a| {
            a.iter()
                .filter_map(|v| v.as_str().map(|s| s.to_string()))
                .collect()
        })
        .unwrap_or_default()
}

pub(super) fn ok<T: Serialize>(value: &T) -> Result<Value, String> {
    let body = serde_json::to_string_pretty(value).map_err(|e| e.to_string())?;
    text(body)
}

pub(super) fn text(body: String) -> Result<Value, String> {
    Ok(json!({ "content": [{ "type": "text", "text": body }] }))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn tool_contract_requires_evidence_and_exposes_binding_mode() {
        let tools = list();
        let complete = tools
            .iter()
            .find(|tool| tool["name"] == "complete_task")
            .unwrap();
        assert!(complete["inputSchema"]["required"]
            .as_array()
            .unwrap()
            .iter()
            .any(|value| value == "evidence"));
        let link = tools
            .iter()
            .find(|tool| tool["name"] == "link_goal_to_code")
            .unwrap();
        assert_eq!(
            link["inputSchema"]["properties"]["mode"]["default"],
            "governed"
        );
        let create = tools
            .iter()
            .find(|tool| tool["name"] == "create_task")
            .unwrap();
        assert!(create["inputSchema"]["properties"]["blocked_by"].is_object());
    }
}
